"""Tkinter GUI for the Library Management System."""import tkinter as tkfrom tkinter import ttk, messagebox, simpledialogfrom datetime import datetimefrom ..collections.book_collection import BookCollectionfrom ..collections.member_collection import MemberCollectionfrom ..collections.loan_collection import LoanCollectionfrom ..services.loan_service import LoanServicefrom ..models.book import Bookfrom ..models.member import Memberfrom ..persistence import save_data, load_dataclass LibraryGUI:    """Main GUI application window."""    def __init__(self, root):        self.root = root        self.root.title("Library Management System")        self.root.geometry("900x600")        # Initialize status variable FIRST        self.status_var = tk.StringVar()        self.status_var.set("Ready")        # Initialize collections        self.books = BookCollection()        self.members = MemberCollection()        self.loans = LoanCollection()        # Load saved data if exists        try:            loaded = load_data()            if loaded:                self.books, self.members, self.loans = loaded        except Exception:            pass  # Start fresh if no save file        self.loan_service = LoanService(self.books, self.members, self.loans)        self._initialize_sample_data()        self._create_widgets()        self._refresh_book_list()        self._refresh_member_list()        self._refresh_loans_list()    def _initialize_sample_data(self):        """Seed the system with starter data if empty."""        if self.books.count() == 0:            sample_books = [                Book("The Great Gatsby", "F. Scott Fitzgerald", "978-0743273565", 1925),                Book("To Kill a Mockingbird", "Harper Lee", "978-0446310789", 1960),                Book("1984", "George Orwell", "978-0451524935", 1949),                Book("Clean Code", "Robert C. Martin", "978-0132350884", 2008, is_reference=True),            ]            for book in sample_books:                try:                    self.books.add_book(book)                except ValueError:                    pass        if self.members.count() == 0:            sample_members = [                Member("Alice Johnson", "M001", "alice@email.com", "555-0101"),                Member("Bob Smith", "M002", "bob@email.com", "555-0102"),                Member("Carol Davis", "M003", "carol@email.com", "555-0103"),            ]            for member in sample_members:                try:                    self.members.add_member(member)                except ValueError:                    pass    # ----------------------------------------------------------------------    # UI Creation    # ----------------------------------------------------------------------    def _create_widgets(self):        # Notebook (tabs)        notebook = ttk.Notebook(self.root)        notebook.pack(fill='both', expand=True, padx=10, pady=10)        # Books Tab        self.books_frame = ttk.Frame(notebook)        notebook.add(self.books_frame, text='Books')        self._setup_books_tab()        # Members Tab        self.members_frame = ttk.Frame(notebook)        notebook.add(self.members_frame, text='Members')        self._setup_members_tab()        # Loans Tab        self.loans_frame = ttk.Frame(notebook)        notebook.add(self.loans_frame, text='Loans')        self._setup_loans_tab()        # Reports Tab        self.reports_frame = ttk.Frame(notebook)        notebook.add(self.reports_frame, text='Reports')        self._setup_reports_tab()        # Status Bar        status_bar = ttk.Label(self.root, textvariable=self.status_var, relief=tk.SUNKEN, anchor=tk.W)        status_bar.pack(side=tk.BOTTOM, fill=tk.X)    # ----------------------------------------------------------------------    # Books Tab    # ----------------------------------------------------------------------    def _setup_books_tab(self):        # Book list (Treeview)        columns = ('isbn', 'title', 'author', 'year', 'status')        self.books_tree = ttk.Treeview(self.books_frame, columns=columns, show='headings', height=15)        self.books_tree.heading('isbn', text='ISBN')        self.books_tree.heading('title', text='Title')        self.books_tree.heading('author', text='Author')        self.books_tree.heading('year', text='Year')        self.books_tree.heading('status', text='Status')        self.books_tree.column('isbn', width=120)        self.books_tree.column('title', width=250)        self.books_tree.column('author', width=150)        self.books_tree.column('year', width=60)        self.books_tree.column('status', width=100)        scrollbar = ttk.Scrollbar(self.books_frame, orient=tk.VERTICAL, command=self.books_tree.yview)        self.books_tree.configure(yscrollcommand=scrollbar.set)        self.books_tree.grid(row=0, column=0, sticky='nsew')        scrollbar.grid(row=0, column=1, sticky='ns')        # Buttons        btn_frame = ttk.Frame(self.books_frame)        btn_frame.grid(row=1, column=0, columnspan=2, pady=10)        ttk.Button(btn_frame, text="Add Book", command=self._add_book_dialog).pack(side=tk.LEFT, padx=5)        ttk.Button(btn_frame, text="Remove Book", command=self._remove_book).pack(side=tk.LEFT, padx=5)        ttk.Button(btn_frame, text="Refresh", command=self._refresh_book_list).pack(side=tk.LEFT, padx=5)        ttk.Button(btn_frame, text="Save Data", command=self._save_all_data).pack(side=tk.LEFT, padx=5)        self.books_frame.columnconfigure(0, weight=1)        self.books_frame.rowconfigure(0, weight=1)    def _refresh_book_list(self):        for item in self.books_tree.get_children():            self.books_tree.delete(item)        for book in self.books.get_all_books():            status = "Available" if book.is_available() else "Checked Out"            self.books_tree.insert('', tk.END, values=(                book.isbn, book.title, book.author, book.publication_year, status            ))        self.status_var.set(f"Total books: {self.books.count()}")    def _add_book_dialog(self):        dialog = tk.Toplevel(self.root)        dialog.title("Add New Book")        dialog.geometry("400x300")        dialog.grab_set()        ttk.Label(dialog, text="Title:").pack(pady=5)        title_entry = ttk.Entry(dialog, width=40)        title_entry.pack()        ttk.Label(dialog, text="Author:").pack(pady=5)        author_entry = ttk.Entry(dialog, width=40)        author_entry.pack()        ttk.Label(dialog, text="ISBN:").pack(pady=5)        isbn_entry = ttk.Entry(dialog, width=40)        isbn_entry.pack()        ttk.Label(dialog, text="Publication Year:").pack(pady=5)        year_entry = ttk.Entry(dialog, width=40)        year_entry.pack()        ref_var = tk.BooleanVar()        ttk.Checkbutton(dialog, text="Reference Only", variable=ref_var).pack(pady=5)        def submit():            try:                title = title_entry.get().strip()                author = author_entry.get().strip()                isbn = isbn_entry.get().strip()                year = int(year_entry.get())                if not title or not author or not isbn:                    raise ValueError("All fields are required")                book = Book(title, author, isbn, year, is_reference=ref_var.get())                self.books.add_book(book)                self._refresh_book_list()                dialog.destroy()                messagebox.showinfo("Success", f"Book '{title}' added.")            except ValueError as e:                messagebox.showerror("Error", str(e))        ttk.Button(dialog, text="Add Book", command=submit).pack(pady=20)    def _remove_book(self):        selected = self.books_tree.selection()        if not selected:            messagebox.showwarning("No Selection", "Please select a book to remove.")            return        item = self.books_tree.item(selected[0])        isbn = item['values'][0]        try:            book = self.books.remove_book(isbn)            self._refresh_book_list()            messagebox.showinfo("Success", f"Book '{book.title}' removed.")        except Exception as e:            messagebox.showerror("Error", str(e))    # ----------------------------------------------------------------------    # Members Tab    # ----------------------------------------------------------------------    def _setup_members_tab(self):        columns = ('id', 'name', 'email', 'phone', 'borrowed', 'fines')        self.members_tree = ttk.Treeview(self.members_frame, columns=columns, show='headings', height=15)        self.members_tree.heading('id', text='Member ID')        self.members_tree.heading('name', text='Name')        self.members_tree.heading('email', text='Email')        self.members_tree.heading('phone', text='Phone')        self.members_tree.heading('borrowed', text='Books')        self.members_tree.heading('fines', text='Fines')        scrollbar = ttk.Scrollbar(self.members_frame, orient=tk.VERTICAL, command=self.members_tree.yview)        self.members_tree.configure(yscrollcommand=scrollbar.set)        self.members_tree.grid(row=0, column=0, sticky='nsew')        scrollbar.grid(row=0, column=1, sticky='ns')        btn_frame = ttk.Frame(self.members_frame)        btn_frame.grid(row=1, column=0, columnspan=2, pady=10)        ttk.Button(btn_frame, text="Add Member", command=self._add_member_dialog).pack(side=tk.LEFT, padx=5)        ttk.Button(btn_frame, text="Pay Fine", command=self._pay_fine_dialog).pack(side=tk.LEFT, padx=5)        ttk.Button(btn_frame, text="Refresh", command=self._refresh_member_list).pack(side=tk.LEFT, padx=5)        self.members_frame.columnconfigure(0, weight=1)        self.members_frame.rowconfigure(0, weight=1)    def _refresh_member_list(self):        for item in self.members_tree.get_children():            self.members_tree.delete(item)        for m in self.members.get_all_members():            self.members_tree.insert('', tk.END, values=(                m.member_id, m.name, m.email, m.phone,                m.get_borrowed_count(), f"${m.get_fines_owed():.2f}"            ))        self.status_var.set(f"Total members: {self.members.count()}")    def _add_member_dialog(self):        dialog = tk.Toplevel(self.root)        dialog.title("Register New Member")        dialog.geometry("400x300")        dialog.grab_set()        ttk.Label(dialog, text="Name:").pack(pady=5)        name_entry = ttk.Entry(dialog, width=40)        name_entry.pack()        ttk.Label(dialog, text="Member ID:").pack(pady=5)        id_entry = ttk.Entry(dialog, width=40)        id_entry.pack()        ttk.Label(dialog, text="Email:").pack(pady=5)        email_entry = ttk.Entry(dialog, width=40)        email_entry.pack()        ttk.Label(dialog, text="Phone:").pack(pady=5)        phone_entry = ttk.Entry(dialog, width=40)        phone_entry.pack()        def submit():            try:                name = name_entry.get().strip()                member_id = id_entry.get().strip()                email = email_entry.get().strip()                phone = phone_entry.get().strip()                if not name or not member_id or not email:                    raise ValueError("Name, ID, and Email are required")                member = Member(name, member_id, email, phone)                self.members.add_member(member)                self._refresh_member_list()                dialog.destroy()                messagebox.showinfo("Success", f"Member '{name}' registered.")            except ValueError as e:                messagebox.showerror("Error", str(e))        ttk.Button(dialog, text="Register", command=submit).pack(pady=20)    def _pay_fine_dialog(self):        selected = self.members_tree.selection()        if not selected:            messagebox.showwarning("No Selection", "Please select a member.")            return        item = self.members_tree.item(selected[0])        member_id = item['values'][0]        member = self.members.find_by_id(member_id)        if member.get_fines_owed() == 0.0:            messagebox.showinfo("No Fines", "This member has no fines to pay.")            return        amount = simpledialog.askfloat("Pay Fine",                                       f"Current fines: ${member.get_fines_owed():.2f}\nEnter payment amount:",                                       minvalue=0.0, maxvalue=member.get_fines_owed())        if amount is not None:            paid = member.pay_fine(amount)            self._refresh_member_list()            messagebox.showinfo("Payment", f"Paid ${paid:.2f}. Remaining: ${member.get_fines_owed():.2f}")    # ----------------------------------------------------------------------    # Loans Tab    # ----------------------------------------------------------------------    def _setup_loans_tab(self):        # Checkout Frame        checkout_frame = ttk.LabelFrame(self.loans_frame, text="Check Out Book")        checkout_frame.pack(fill='x', padx=10, pady=5)        ttk.Label(checkout_frame, text="Member ID:").grid(row=0, column=0, padx=5, pady=5)        self.checkout_member_entry = ttk.Entry(checkout_frame, width=20)        self.checkout_member_entry.grid(row=0, column=1, padx=5, pady=5)        ttk.Label(checkout_frame, text="Book ISBN:").grid(row=0, column=2, padx=5, pady=5)        self.checkout_isbn_entry = ttk.Entry(checkout_frame, width=20)        self.checkout_isbn_entry.grid(row=0, column=3, padx=5, pady=5)        ttk.Button(checkout_frame, text="Check Out", command=self._checkout_book).grid(row=0, column=4, padx=10)        # Checkin Frame        checkin_frame = ttk.LabelFrame(self.loans_frame, text="Check In Book")        checkin_frame.pack(fill='x', padx=10, pady=5)        ttk.Label(checkin_frame, text="Member ID:").grid(row=0, column=0, padx=5, pady=5)        self.checkin_member_entry = ttk.Entry(checkin_frame, width=20)        self.checkin_member_entry.grid(row=0, column=1, padx=5, pady=5)        ttk.Label(checkin_frame, text="Book ISBN:").grid(row=0, column=2, padx=5, pady=5)        self.checkin_isbn_entry = ttk.Entry(checkin_frame, width=20)        self.checkin_isbn_entry.grid(row=0, column=3, padx=5, pady=5)        ttk.Button(checkin_frame, text="Check In", command=self._checkin_book).grid(row=0, column=4, padx=10)        # Active Loans List        list_frame = ttk.LabelFrame(self.loans_frame, text="Active Loans")        list_frame.pack(fill='both', expand=True, padx=10, pady=5)        columns = ('book', 'member', 'due', 'status')        self.loans_tree = ttk.Treeview(list_frame, columns=columns, show='headings', height=10)        self.loans_tree.heading('book', text='Book')        self.loans_tree.heading('member', text='Member')        self.loans_tree.heading('due', text='Due Date')        self.loans_tree.heading('status', text='Status')        scrollbar = ttk.Scrollbar(list_frame, orient=tk.VERTICAL, command=self.loans_tree.yview)        self.loans_tree.configure(yscrollcommand=scrollbar.set)        self.loans_tree.pack(side=tk.LEFT, fill='both', expand=True)        scrollbar.pack(side=tk.RIGHT, fill='y')        ttk.Button(self.loans_frame, text="Refresh Loans", command=self._refresh_loans_list).pack(pady=5)    def _checkout_book(self):        member_id = self.checkout_member_entry.get().strip()        isbn = self.checkout_isbn_entry.get().strip()        if not member_id or not isbn:            messagebox.showwarning("Input Error", "Please enter Member ID and Book ISBN.")            return        success, msg, _ = self.loan_service.check_out_book(member_id, isbn)        if success:            messagebox.showinfo("Success", msg)            self._refresh_book_list()            self._refresh_member_list()            self._refresh_loans_list()            self.checkout_member_entry.delete(0, tk.END)            self.checkout_isbn_entry.delete(0, tk.END)        else:            messagebox.showerror("Error", msg)    def _checkin_book(self):        member_id = self.checkin_member_entry.get().strip()        isbn = self.checkin_isbn_entry.get().strip()        if not member_id or not isbn:            messagebox.showwarning("Input Error", "Please enter both Member ID and Book ISBN.")            return        success, msg, _ = self.loan_service.check_in_book(isbn, member_id)        if success:            messagebox.showinfo("Success", msg)            self._refresh_book_list()            self._refresh_member_list()            self._refresh_loans_list()            self.checkin_member_entry.delete(0, tk.END)            self.checkin_isbn_entry.delete(0, tk.END)        else:            messagebox.showerror("Error", msg)    def _refresh_loans_list(self):        for item in self.loans_tree.get_children():            self.loans_tree.delete(item)        for loan in self.loans.get_all_active_loans():            book = self.books.find_by_isbn(loan.book_isbn)            member = self.members.find_by_id(loan.member_id)            book_title = book.title if book else "Unknown"            member_name = member.name if member else "Unknown"            status = "OVERDUE" if loan.is_overdue() else "Active"            self.loans_tree.insert('', tk.END, values=(                book_title, member_name, loan.due_date.strftime('%Y-%m-%d'), status            ))    # ----------------------------------------------------------------------    # Reports Tab    # ----------------------------------------------------------------------    def _setup_reports_tab(self):        ttk.Button(self.reports_frame, text="Show Statistics", command=self._show_stats).pack(pady=10)        ttk.Button(self.reports_frame, text="Members with Fines", command=self._show_members_with_fines).pack(pady=10)        ttk.Button(self.reports_frame, text="Save Data", command=self._save_all_data).pack(pady=10)    def _show_stats(self):        stats = (            f"Total Books: {self.books.count()}\n"            f"Available Books: {self.books.count_available()}\n"            f"Checked Out: {self.books.count() - self.books.count_available()}\n"            f"Total Members: {self.members.count()}\n"            f"Active Loans: {self.loans.count_active()}\n"            f"Overdue Loans: {len(self.loans.get_overdue_loans())}"        )        messagebox.showinfo("Library Statistics", stats)    def _show_members_with_fines(self):        members = self.members.get_members_with_fines()        if not members:            messagebox.showinfo("Members with Fines", "No members have outstanding fines.")            return        text = "\n".join([f"{m.name} (ID: {m.member_id}): ${m.get_fines_owed():.2f}" for m in members])        messagebox.showinfo("Members with Fines", text)    def _save_all_data(self):        try:            save_data(self.books, self.members, self.loans)            self.status_var.set("Data saved successfully.")        except Exception as e:            messagebox.showerror("Save Error", str(e))def run_gui():    root = tk.Tk()    app = LibraryGUI(root)    root.mainloop()